module sr_latch (
    input wire Invalid_S,
    input wire R,
    output reg Q,
    output reg Qn
);
    always @ (Invalid_S or R) begin
        if (Invalid_S && ~R) begin
            Q <= 1;
            Qn <= 0;
        end else if (~Invalid_S && R) begin
            Q <= 0;
            Qn <= 1;
        end else if (~Invalid_S && ~R) begin
            // retain previous state
            Q <= Q;
            Qn <= Qn;
        end else begin
            // invalid state, hold previous state
            Q <= Q;
            Qn <= Qn;
        end
    end
endmodule
